import os
from flask import Flask, send_from_directory, url_for
from werkzeug.utils import secure_filename

app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = 'uploads'
app.config['MAX_CONTENT_LENGTH'] = 16 * 1024 * 1024

# Legacy file mapping dictionary for backward compatibility
LEGACY_MAPPING = {
    'old_file1.txt': 'new_file1.txt',
    'old_file2.pdf': 'new_file2.pdf',
    'old_image.jpg': 'new_image.jpg'
}

@app.route('/legacy/<path:filename>')
def legacy_static(filename):
    """Serve static files with backward compatibility support"""
    # Check if filename is in legacy mapping
    if filename in LEGACY_MAPPING:
        # Return the mapped filename
        mapped_filename = LEGACY_MAPPING[filename]
        return send_from_directory(app.config['UPLOAD_FOLDER'], mapped_filename)
    
    # Check if file exists in uploads directory
    if os.path.exists(os.path.join(app.config['UPLOAD_FOLDER'], filename)):
        return send_from_directory(app.config['UPLOAD_FOLDER'], filename)
    
    # If file doesn't exist, try with legacy naming convention
    legacy_filename = filename
    if not filename.endswith('.txt') and not filename.endswith('.pdf') and not filename.endswith('.jpg'):
        # Try common legacy extensions
        for ext in ['.txt', '.pdf', '.jpg', '.png', '.gif']:
            if os.path.exists(os.path.join(app.config['UPLOAD_FOLDER'], filename + ext)):
                return send_from_directory(app.config['UPLOAD_FOLDER'], filename + ext)
    
    # File not found
    return "File not found", 404

@app.route('/uploads/<path:filename>')
def uploads(filename):
    """Serve static files from uploads directory"""
    return send_from_directory(app.config['UPLOAD_FOLDER'], filename)

# Ensure uploads directory exists
os.makedirs(app.config['UPLOAD_FOLDER'], exist_ok=True)